const numbersToWords=D=>{const p=['','ένα','δύο','τρία','τέσσερα','πέντε','έξι','επτά','οκτώ','εννέα','δέκα','έντεκα','δώδεκα','δεκατρία','δεκατέσσερα','δεκαπέντε','δεκαέξι','δεκαεπτά','δεκαοκτώ','δεκαεννέα'];if(D<0x14)return p[D];if(D<0x64)return['','','είκοσι','τριάντα','σαράντα','πενήντα','εξήντα','εβδομήντα','ογδόντα','ενενήντα'][Math['floor'](D/0xa)]+(D%0xa?'\x20'+p[D%0xa]:'');if(D<0x3e8){const g=Math['floor'](D/0x64),i=D%0x64;return(0x1===g?'εκατό':0x2===g?'διακόσια':0x3===g?'τριακόσια':0x4===g?'τετρακόσια':0x5===g?'πεντακόσια':0x6===g?'εξακόσια':0x7===g?'επτακόσια':0x8===g?'οκτακόσια':0x9===g?'εννιακόσια':'')+(i?'\x20'+numbersToWords(i):'');}return D<0xf4240?numbersToWords(Math['floor'](D/0x3e8))+'\x20χιλιάδες'+(D%0x3e8?'\x20'+numbersToWords(D%0x3e8):''):numbersToWords(Math['floor'](D/0xf4240))+'\x20εκατομμύρια'+(D%0xf4240?'\x20'+numbersToWords(D%0xf4240):'');},numberToText=(D,p='money')=>{const g=Math['floor'](D),i=Math['round'](0x64*(D-g));let d=numbersToWords(g),P=i>0x0?numbersToWords(i):'';switch(p){case'money':return P?d+'\x20ευρώ\x20και\x20'+P+'\x20λεπτά':d+'\x20ευρώ';case'time':return P?d+'\x20ώρες\x20και\x20'+P+'\x20λεπτά':d+'\x20ώρες';default:return P?d+'\x20και\x20'+P:''+d;}};